module RefModule (clk, clr, en, q);
   input clk, clr, en;
   output [2:0] q;

   reg [2:0] q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge clr or posedge dbg_halt) begin
    if (clr) begin
        q <= 3'b000;
    end else if (en) begin
        q <= q + 1;
    end
end

endmodule
